INSERT INTO "ExerciseRecord" ("id", "data", "createdAt", "updatedAt") VALUES
('farbenpass-kompass', '{"id":"farbenpass-kompass","title":"Farbenpass-Kompass","description":"Nach einem Farbzeichen lösen sich die Kinder vom Zentrum, spielen durch das passende Passtor und besetzen eine neue Position.","duration":12,"players":"8–16","ageGroup":"F-Jugend","ageRange":"U8/U9","category":"Einstieg","accent":"#58a6ff","intensity":"Mittel","focus":["Passspiel","Wahrnehmung"],"setup":"Vier farblich markierte Hütchentore als Kompass um ein 16 × 16 m großes Zentrum stellen. Je zwei bis vier Kinder starten an jeder Seite.","coaching":["Vor der Ballannahme zur Farbe orientieren","Flach durch das Tor passen","Nach dem Pass sofort eine freie Seite anlaufen"],"materials":[{"id":"balls","count":4},{"id":"cones","count":16}],"fieldSize":"20 × 20 m","variant":20}'::jsonb, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('drei-gegen-drei-chaosstart', '{"id":"drei-gegen-drei-chaosstart","title":"3 gegen 3 – Chaosstart","description":"Beide Teams starten aus unterschiedlichen Ecken. Der Trainer eröffnet jede Runde neu, sodass sofort überraschende Duelle entstehen.","duration":15,"players":"6–12","ageGroup":"F-Jugend","ageRange":"U9","category":"Hauptteil","accent":"#f5c451","intensity":"Hoch","focus":["Orientierung","Umschalten"],"setup":"Ein 22 × 18 m großes Feld mit vier Dribbeltoren markieren. Drei Kinder pro Team verteilen sich diagonal in den Ecken.","coaching":["Nach dem Startsignal zuerst den Raum erkennen","Mutig ins freie Tor dribbeln","Nach Ballverlust direkt weiterspielen"],"materials":[{"id":"balls","count":8},{"id":"cones","count":16},{"id":"bibs","count":6}],"fieldSize":"22 × 18 m","variant":21}'::jsonb, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('dribbeltor-bumerang', '{"id":"dribbeltor-bumerang","title":"Dribbeltor-Bumerang","description":"Die Kinder durchdribbeln ein Tor, wenden dahinter und suchen mit hohem Tempo ein anderes freies Tor.","duration":10,"players":"6–16","ageGroup":"F-Jugend","ageRange":"U8/U9","category":"Ankommen","accent":"#45d875","intensity":"Mittel","focus":["Dribbling","Richtungswechsel"],"setup":"Sechs kleine Hütchentore sternförmig in einem 22 × 22 m großen Feld verteilen. Jedes Kind hat einen Ball.","coaching":["Vor dem Tor den Kopf heben","Eng durch das Tor führen","Nach der Wende deutlich beschleunigen"],"materials":[{"id":"balls","count":16},{"id":"cones","count":12}],"fieldSize":"22 × 22 m","variant":22}'::jsonb, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('inselwechsel-mit-ball', '{"id":"inselwechsel-mit-ball","title":"Inselwechsel mit Ball","description":"Vier Teams tauschen auf ein Signal ihre Insel. Punkte gibt es für kontrolliertes Dribbling und eine freie Zielinsel.","duration":10,"players":"8–16","ageGroup":"F-Jugend","ageRange":"U8","category":"Ankommen","accent":"#45d875","intensity":"Mittel","focus":["Ballgefühl","Reaktion"],"setup":"Vier 4 × 4 m große Inseln in den Ecken eines 20 × 20 m großen Feldes markieren. Ein Ball pro Kind.","coaching":["Ball beim Start nah am Fuß halten","Zusammenstöße in der Mitte vermeiden","Freie Wege selbst entdecken"],"materials":[{"id":"balls","count":16},{"id":"cones","count":16}],"fieldSize":"20 × 20 m","variant":23}'::jsonb, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('torschuss-pendel', '{"id":"torschuss-pendel","title":"Torschuss-Pendel","description":"Nach einem kurzen Zuspiel nimmt das Kind den Ball in die Bewegung mit und schließt abwechselnd auf zwei Tore ab.","duration":12,"players":"6–14","ageGroup":"F-Jugend","ageRange":"U8/U9","category":"Einstieg","accent":"#58a6ff","intensity":"Mittel","focus":["Torschuss","Erster Kontakt"],"setup":"Zwei Minitore gegenüber aufstellen. In der Mitte zwei Startpositionen mit je einer Passstation markieren.","coaching":["Ersten Kontakt in Richtung Tor mitnehmen","Vor dem Abschluss kurz aufschauen","Rechts und links im Wechsel schießen"],"materials":[{"id":"balls","count":8},{"id":"cones","count":6},{"id":"miniGoals","count":2}],"fieldSize":"24 × 14 m","variant":24}'::jsonb, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('dreieck-vier-gegen-eins', '{"id":"dreieck-vier-gegen-eins","title":"Dreieck: 4 gegen 1","description":"Vier Kinder halten den Ball an drei Außenseiten gegen einen Balljäger und dürfen freie Seiten jederzeit neu besetzen.","duration":12,"players":"5–15","ageGroup":"F-Jugend","ageRange":"U9","category":"Hauptteil","accent":"#f5c451","intensity":"Mittel","focus":["Freilaufen","Passspiel"],"setup":"Pro Gruppe ein etwa 10 m großes Hütchendreieck markieren. Vier Ballbesitzer spielen gegen einen Balljäger.","coaching":["Immer zwei Passwege anbieten","Ball mit maximal drei Kontakten weiterspielen","Nach einem Pass eine neue Seite besetzen"],"materials":[{"id":"balls","count":3},{"id":"cones","count":9},{"id":"bibs","count":3}],"fieldSize":"3 × Dreieck 10 m","variant":25}'::jsonb, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)
